 function checkReferrer(){
 try{
 var referrer = window.parent.document.referrer;
 var domain = "law.go.kr".toUpperCase();
 var nwYn = 'Y';
 var rrClsCd = '110409';
 var efYd = '20251001';
 var lapYd = '';
 var apiGubun = '';
 var existLsIdCnt = $('input[id=existLsIdCnt]').val();

var today = new Date();
 var todayStr = '' + today.getFullYear()
 + String(today.getMonth() + 1).padStart(2, '0')
 + String(today.getDate()).padStart(2, '0');

if(apiGubun == 'api'){ 
 referrer = window.location.href;
 }
 if( !referrer ){
 closeInfoPModal();
 } else {
 var hostName = referrer.split('/')[2]; 
 var viewCls = getViewClsFromUrl(referrer);
 if( hostName.toUpperCase().indexOf(domain) > -1 && apiGubun != 'api'){
 closeInfoPModal();
 } else {
 if( nwYn == "Y" ){
 closeInfoPModal();
 } else if ( rrClsCd == "110404" || rrClsCd == "110407" || rrClsCd == "110410" ) { //폐지여부체크
 if (efYd != "99991231" && efYd > todayStr) {
 modal('lsInfoPModal', '이 법은 현행이 아닙니다.', 'LsCurMove' , '현행법령이동', existLsIdCnt);
 } else {
 modal('lsInfoPModal', '이 법은 페지된 법령입니다.');
 }
 } else if (lapYd != '' && lapYd <= todayStr) {
 if (existLsIdCnt > 0){
 modal('lsInfoPModal', '이 법은 페지된 법령입니다.', 'LsCurMove' , '현행법령이동', existLsIdCnt);
 } else {
 modal('lsInfoPModal', '이 법은 페지된 법령입니다.');
 }
 } else {
 if( !viewCls || viewCls == "lsInfoP" ){
 viewCls = getViewClsFromUrl(location.href);
 if( !viewCls || viewCls == "lsInfoP" ){
 modal('lsInfoPModal', '이 법은 현행이 아닙니다.', 'LsCurMove' , '현행법령이동', existLsIdCnt);
 } else {
 closeInfoPModal(); 
 }
 } else {
 closeInfoPModal();
 } 
 }
 } 
 }
 }catch(e){
 console.log(e);
 closeInfoPModal();
 }
 }

function getViewClsFromUrl(url){
 var parser = document.createElement("a");
 parser.href = url;
 var search = parser.search.substring(1);
 var viewCls = "";
 if(search){
 viewCls = getUrlParam(search, "viewCls");
 }
 return viewCls;
 }

 function getUrlParam(search, paramName){
 var paramValue = "";
 var params = search.split("&");
 var searchParams = {};

 for(var i=0; i < params.length; i++){
 var searchParam = params[i].split("=");
 searchParams[searchParam[0]] = searchParam[1];
 }
 if( searchParams[paramName] ){
 paramValue = searchParams[paramName];
 }
 return paramValue;
 }

